// Get the PDF text from previous node
const pdfText = $json["text"];

// Remove repeated document titles
let cleanText = pdfText.replace(/Process Design Document – Process Vendor Invoices for Vendor for ACME Systems Inc\./g, '');

// Remove multiple new lines
cleanText = cleanText.replace(/\n\s*\n/g, '\n');

// Optionally remove page numbers (lines with only digits)
cleanText = cleanText.replace(/^\d+\s*$/gm, '');

// Trim spaces
cleanText = cleanText.trim();

return [{ json: { cleanText } }];

// 1. Extract the raw text from OpenAI output
const rawText =
  $json.output[0].content[0].text;

// 2. Parse JSON safely
let proposal;
try {
  proposal = JSON.parse(rawText);
} catch (e) {
  throw new Error("OpenAI output is not valid JSON");
}

// 3. Compute risk flag (one PDF = one decision)
const risk_flagged =
  Array.isArray(proposal.risks_or_concerns) &&
  proposal.risks_or_concerns.length > 0;

// 4. Return EXACTLY ONE ITEM
return [
  {
    json: {
      vendor_name: proposal.vendor_name,
      category: proposal.category,
      summary: proposal.summary,
      key_points: proposal.key_points,
      risks_or_concerns: proposal.risks_or_concerns,
      risk_flagged
    }
  }
];

const data = $json;

return [{
  json: {
    title: `⚠️ Risks Identified in ${data.vendor_name} Proposal`,
    vendor: data.vendor_name,
    category: data.category,
    summary: data.summary,
    risk_count: data.risks_or_concerns.length,
    risks: data.risks_or_concerns.map((risk, i) => `${i + 1}. ${risk}`),
    action_required: "Manual review required before approval"
  }
}];

return [{
  json: {
    vendor_name: $json.vendor_name,
    status: "APPROVED",
    message: "No risks found. Proposal approved."
  }
}];
